const LINEAR_ISSUES = 'https://synchrosocial.app.n8n.cloud/webhook/linear-issues';
let resp;
try {
  resp = await this.helpers.httpRequest({ method: 'GET', url: LINEAR_ISSUES, json: true, timeout: 60000 });
} catch (e) {
  // Read failed — skip ALL writes this run. Never mass-deactivate on a bad read.
  return [];
}
const issues = (resp && Array.isArray(resp.issues)) ? resp.issues : [];
// Safety gate: an empty/failed sweep must NOT reach the mark-sweep (it would
// deactivate every row). Only proceed when we actually received issues.
if (!issues.length) return [];
const runStart = new Date().toISOString();
const rows = issues.map((i) => ({
  id: i.id,
  identifier: i.identifier == null ? null : i.identifier,
  title: i.title == null ? null : i.title,
  url: i.url == null ? null : i.url,
  is_sub_issue: !!i.isSubIssue,
  parent_id: i.parentId == null ? null : i.parentId,
  parent_identifier: i.parentIdentifier == null ? null : i.parentIdentifier,
  due_date: i.dueDate == null ? null : i.dueDate,
  linear_created_at: i.createdAt == null ? null : i.createdAt,
  linear_updated_at: i.updatedAt == null ? null : i.updatedAt,
  status: i.status == null ? null : i.status,
  status_type: i.statusType == null ? null : i.statusType,
  team_key: i.teamKey == null ? null : i.teamKey,
  team_name: i.teamName == null ? null : i.teamName,
  assignee_id: i.assigneeId == null ? null : i.assigneeId,
  assignee_name: i.assigneeName == null ? null : i.assigneeName,
  assignee_email: i.assigneeEmail == null ? null : i.assigneeEmail,
  client_name: i.clientName == null ? null : i.clientName,
  active: true,
  synced_at: runStart,
}));
const seen = new Set();
const deduped = [];
for (const r of rows) { if (!r.id || seen.has(r.id)) continue; seen.add(r.id); deduped.push(r); }
return [{ json: { rows: deduped, runStart, count: deduped.length } }];
